import React, { useState } from 'react';
import Card from '../../components/common/Card';
import Badge from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Modal from '../../components/common/Modal';
import Alert from '../../components/common/Alert';
import Input, { Select, Textarea } from '../../components/common/Input';
import Spinner from '../../components/common/Spinner';
import { useLeaves, useLeaveBalance } from '../../hooks/useLeave';
import { useAuth } from '../../context/AuthContext';
import leaveService from '../../services/leaveService';
import { formatDate } from '../../utils/formatters';
import { LEAVE_TYPES, LEAVE_STATUS } from '../../constants';
import './LeavePage.css';

const LeavePage = () => {
  const { isAdminOrManager } = useAuth();
  const [page, setPage] = useState(1);
  const { leaves, pagination, loading, refresh } = useLeaves({ page, limit: 10 });
  const { balance, refresh: refreshBalance } = useLeaveBalance();
  const [showModal, setShowModal] = useState(false);
  const [form, setForm]     = useState({ type: '', startDate: '', endDate: '', reason: '' });
  const [formLoading, setFormLoading] = useState(false);
  const [feedback, setFeedback] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setFormLoading(true);
    try {
      await leaveService.request(form);
      setFeedback({ type: 'success', msg: 'Cererea de concediu a fost trimisă!' });
      setShowModal(false);
      setForm({ type: '', startDate: '', endDate: '', reason: '' });
      refresh(); refreshBalance();
    } catch (err) {
      setFeedback({ type: 'danger', msg: err.message });
    } finally {
      setFormLoading(false);
    }
  };

  const handleCancel = async (id) => {
    if (!window.confirm('Ești sigur că vrei să anulezi această cerere?')) return;
    try {
      await leaveService.cancel(id);
      refresh(); refreshBalance();
      setFeedback({ type: 'success', msg: 'Cerere anulată.' });
    } catch (err) {
      setFeedback({ type: 'danger', msg: err.message });
    }
  };

  return (
    <div className="leave-page">
      {feedback && <Alert type={feedback.type} message={feedback.msg} onClose={() => setFeedback(null)} />}

      {/* Balance cards */}
      {balance && (
        <div className="leave-balance">
          <div className="leave-balance-card">
            <span className="leave-balance-icon">🏖</span>
            <div>
              <p className="leave-balance-label">Concediu odihnă</p>
              <p className="leave-balance-value">{balance.annual} <span>zile</span></p>
            </div>
          </div>
          <div className="leave-balance-card">
            <span className="leave-balance-icon">🏥</span>
            <div>
              <p className="leave-balance-label">Concediu medical</p>
              <p className="leave-balance-value">{balance.sick} <span>zile</span></p>
            </div>
          </div>
        </div>
      )}

      {/* Leave list */}
      <Card padding={false}>
        <Card.Header>
          <span>Cereri concediu</span>
          <Button variant="primary" size="sm" onClick={() => setShowModal(true)}>+ Cerere nouă</Button>
        </Card.Header>
        {loading ? <div className="p-4"><Spinner /></div> : (
          <>
            <div className="leave-table-wrap">
              <table className="leave-table">
                <thead>
                  <tr><th>Tip</th><th>Data start</th><th>Data final</th><th>Zile</th><th>Status</th><th>Acțiuni</th></tr>
                </thead>
                <tbody>
                  {leaves.length === 0 ? (
                    <tr><td colSpan={6} className="table-empty">Nu există cereri de concediu</td></tr>
                  ) : leaves.map((l) => {
                    const st = LEAVE_STATUS[l.status];
                    const leaveType = LEAVE_TYPES.find((t) => t.value === l.type)?.label || l.type;
                    return (
                      <tr key={l.id}>
                        <td>{leaveType}</td>
                        <td>{formatDate(l.startDate)}</td>
                        <td>{formatDate(l.endDate)}</td>
                        <td>{l.days}</td>
                        <td><Badge color={st?.color}>{st?.label}</Badge></td>
                        <td>
                          {['pending', 'approved'].includes(l.status) && (
                            <Button variant="ghost" size="sm" onClick={() => handleCancel(l.id)}>Anulează</Button>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            {pagination.totalPages > 1 && (
              <div className="pagination">
                <Button variant="ghost" size="sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>← Precedent</Button>
                <span className="pagination-info">Pagina {page} din {pagination.totalPages}</span>
                <Button variant="ghost" size="sm" disabled={page >= pagination.totalPages} onClick={() => setPage(p => p + 1)}>Următor →</Button>
              </div>
            )}
          </>
        )}
      </Card>

      {/* New Leave Modal */}
      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title="Cerere nouă concediu"
        footer={
          <>
            <Button variant="ghost" onClick={() => setShowModal(false)}>Anulează</Button>
            <Button variant="primary" loading={formLoading} onClick={handleSubmit} type="submit">Trimite cererea</Button>
          </>
        }
      >
        <form onSubmit={handleSubmit} className="leave-form">
          <Select
            label="Tip concediu" required
            value={form.type}
            onChange={(e) => setForm({ ...form, type: e.target.value })}
            options={LEAVE_TYPES}
            placeholder="Selectează tipul..."
          />
          <div className="leave-form-row">
            <Input label="Data start" type="date" required value={form.startDate} onChange={(e) => setForm({ ...form, startDate: e.target.value })} />
            <Input label="Data final" type="date" required value={form.endDate} onChange={(e) => setForm({ ...form, endDate: e.target.value })} />
          </div>
          <Textarea label="Motiv (opțional)" value={form.reason} onChange={(e) => setForm({ ...form, reason: e.target.value })} rows={3} />
        </form>
      </Modal>
    </div>
  );
};

export default LeavePage;
